package com.the703.basic002_ex;

public class VarEx002 {
	
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a,b;
		a=10;
		b=3;
		System.out.println(a+" + "+b+" = "+(a+b));
		System.out.println(a+"  - "+b+" = "+(a-b));
		System.out.println(a+"  * "+b+" = "+(a*b));
		System.out.println(a+"  / "+b+" = "+(a/b));
		
	}
}
